# ─── Embedded Mascot (base64 PNG) ─────────────────────────────────────────────
WHALE_B64 = """"""

def load_whale_pixmap(size: int) -> QPixmap:
    """Decode the embedded whale PNG and return a circular QPixmap."""
    data = base64.b64decode(WHALE_B64)
    src = QPixmap()
    src.loadFromData(data)
    src = src.scaled(size, size, Qt.KeepAspectRatio, Qt.SmoothTransformation)

    # Create circular mask
    result = QPixmap(size, size)
    result.fill(Qt.transparent)
    painter = QPainter(result)
    painter.setRenderHint(QPainter.Antialiasing)
    path = QPainterPath()
    path.addEllipse(0, 0, size, size)
    painter.setClipPath(path)
    # Center the image
    x = (size - src.width()) // 2
    y = (size - src.height()) // 2
    painter.drawPixmap(x, y, src)
    painter.end()
    return result

