# ─── Hex Grid Background Widget ────────────────────────────────────────────────
class HexGridWidget(QWidget):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setAttribute(Qt.WA_TransparentForMouseEvents)
        self.setAttribute(Qt.WA_NoSystemBackground)
        self.setAutoFillBackground(False)

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.Antialiasing)
        pen = QPen(C_CYAN, 0.8)
        pen.setCosmetic(True)
        painter.setPen(pen)
        painter.setOpacity(0.07)

        hex_w, hex_h = 56, 48
        cols = self.width() // hex_w + 2
        rows = self.height() // hex_h + 2
        for row in range(rows):
            for col in range(cols):
                x = col * hex_w + (hex_w // 2 if row % 2 == 1 else 0)
                y = row * hex_h
                pts = [
                    QPoint(int(x+14), int(y+2)),  QPoint(int(x+42), int(y+2)),
                    QPoint(int(x+56), int(y+24)), QPoint(int(x+42), int(y+46)),
                    QPoint(int(x+14), int(y+46)), QPoint(int(x),    int(y+24)),
                ]
                painter.drawPolygon(QPolygon(pts))

        # Node network
        painter.setOpacity(0.15)
        w, h = self.width(), self.height()
        nodes_pct = [(0.75,0.30),(0.85,0.55),(0.90,0.20),(0.70,0.70),(0.95,0.40),(0.80,0.80)]
        edges = [(0,1),(1,3),(0,4),(4,1),(2,4),(3,5),(1,5)]
        nodes_px = [(int(p[0]*w), int(p[1]*h)) for p in nodes_pct]
        painter.setPen(QPen(C_CYAN, 0.5))
        for a,b in edges:
            painter.drawLine(nodes_px[a][0],nodes_px[a][1],nodes_px[b][0],nodes_px[b][1])
        painter.setBrush(QBrush(C_CYAN))
        painter.setPen(Qt.NoPen)
        for nx,ny in nodes_px:
            painter.drawEllipse(QPoint(nx,ny), 2, 2)
        painter.end()


# ─── Whale Avatar Sidebar Button ───────────────────────────────────────────────
class WhaleAvatarButton(QWidget):
    clicked = __import__("PySide6.QtCore", fromlist=["Signal"]).Signal()

    def __init__(self, parent=None):
        super().__init__(parent)
        self.setFixedSize(52, 62)
        self.setCursor(QCursor(Qt.PointingHandCursor))
        self._active = True
        self._hovered = False
        self._pixmap = load_whale_pixmap(36)

    def setActive(self, v):
        self._active = v
        self.update()

    def mousePressEvent(self, e):
        if e.button() == Qt.LeftButton:
            self.clicked.emit()

    def enterEvent(self, e):
        self._hovered = True; self.update()

    def leaveEvent(self, e):
        self._hovered = False; self.update()

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.Antialiasing)
        w, h = self.width(), self.height()

        if self._active:
            grad = QLinearGradient(0,0,w,h)
            grad.setColorAt(0, QColor("#00b8d4"))
            grad.setColorAt(1, QColor("#0097a7"))
            painter.setBrush(QBrush(grad))
            painter.setPen(Qt.NoPen)
            painter.drawRoundedRect(0, 0, w, h-10, 8, 8)
            # Cyan glow ring around avatar
            painter.setPen(QPen(QColor(0,229,255,180), 1.5))
            painter.setBrush(Qt.NoBrush)
            px_x = (w - 36) // 2
            painter.drawEllipse(px_x-2, 2, 40, 40)

        # Draw whale pixmap centered
        px_x = (w - self._pixmap.width()) // 2
        painter.drawPixmap(px_x, 3, self._pixmap)

        # Label
        color = QColor("#ffffff") if self._active else (C_CYAN if self._hovered else C_TEXT_DIM)
        painter.setPen(QPen(color))
        painter.setFont(QFont("Arial", 7))
        painter.drawText(QRect(0, h-14, w, 12), Qt.AlignHCenter | Qt.AlignVCenter, "AI\nAssist")
        painter.end()


# ─── Regular Sidebar Icon Button ───────────────────────────────────────────────
class SidebarButton(QPushButton):
    def __init__(self, icon_name: str, parent=None):
        super().__init__(parent)
        self.icon_name = icon_name
        self.setFixedSize(52, 52)
        self.setCursor(QCursor(Qt.PointingHandCursor))
        self._active = False
        self._hovered = False

    def setActive(self, active):
        self._active = active; self.update()

    def enterEvent(self, e):
        self._hovered = True; self.update(); super().enterEvent(e)

    def leaveEvent(self, e):
        self._hovered = False; self.update(); super().leaveEvent(e)

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.Antialiasing)
        w, h = self.width(), self.height()

        if self._active:
            grad = QLinearGradient(0,0,w,h)
            grad.setColorAt(0, QColor("#00b8d4"))
            grad.setColorAt(1, QColor("#0097a7"))
            painter.setBrush(QBrush(grad))
            painter.setPen(Qt.NoPen)
            painter.drawRoundedRect(0,0,w,h,8,8)
        else:
            painter.setBrush(Qt.NoBrush)
            painter.setPen(Qt.NoPen)

        color = QColor("#ffffff") if self._active else (C_CYAN if self._hovered else C_TEXT_DIM)
        painter.setPen(QPen(color, 1.5, Qt.SolidLine, Qt.RoundCap, Qt.RoundJoin))
        painter.setBrush(Qt.NoBrush)
        self._draw_icon(painter, w//2, h//2, color)
        painter.end()

    def _draw_icon(self, painter, cx, cy, color):
        s = 9
        painter.setPen(QPen(color, 1.5, Qt.SolidLine, Qt.RoundCap, Qt.RoundJoin))
        if self.icon_name == "shield":
            path = QPainterPath()
            path.moveTo(cx, cy-s); path.lineTo(cx-s, cy-s//2)
            path.lineTo(cx-s, cy+2); path.quadTo(cx-s,cy+s, cx,cy+s+2)
            path.quadTo(cx+s,cy+s, cx+s,cy+2); path.lineTo(cx+s,cy-s//2); path.closeSubpath()
            painter.drawPath(path)
        elif self.icon_name == "doc":
            painter.drawRoundedRect(cx-s+2,cy-s,s*2-2,s*2,1,1)
            painter.drawLine(cx-3,cy-3,cx+4,cy-3); painter.drawLine(cx-3,cy,cx+2,cy); painter.drawLine(cx-3,cy+3,cx,cy+3)
        elif self.icon_name == "scan":
            d=5
            for sx,sy in [(cx-s,cy-s),(cx+s,cy-s),(cx-s,cy+s),(cx+s,cy+s)]:
                dx = d if sx < cx else -d
                dy = d if sy < cy else -d
                painter.drawLine(sx,sy,sx+dx,sy); painter.drawLine(sx,sy,sx,sy+dy)
            painter.setPen(QPen(color, 1.0)); painter.drawLine(cx-s,cy,cx+s,cy)
        elif self.icon_name == "plugin":
            painter.drawRoundedRect(cx-s,cy-s,s-1,s-1,1,1); painter.drawRoundedRect(cx+1,cy-s,s-1,s-1,1,1)
            painter.drawRoundedRect(cx-s,cy+1,s-1,s-1,1,1); painter.drawRoundedRect(cx+1,cy+1,s-1,s-1,1,1)
        elif self.icon_name == "db":
            painter.drawEllipse(cx-s,cy-s,s*2,5)
            painter.drawLine(cx-s,cy-s+2,cx-s,cy); painter.drawLine(cx+s,cy-s+2,cx+s,cy)
            painter.drawEllipse(cx-s,cy-2,s*2,5)
            painter.drawLine(cx-s,cy+1,cx-s,cy+s-1); painter.drawLine(cx+s,cy+1,cx+s,cy+s-1)
            painter.drawEllipse(cx-s,cy+s-3,s*2,5)


# ─── AI Message with Whale Avatar ──────────────────────────────────────────────
class AIMessageWidget(QWidget):
    _whale_px = None  # class-level cache

    def __init__(self, text: str, time_str: str, parent=None):
        super().__init__(parent)
        if AIMessageWidget._whale_px is None:
            AIMessageWidget._whale_px = load_whale_pixmap(32)

        self.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Minimum)
        layout = QHBoxLayout(self)
        layout.setContentsMargins(0, 4, 0, 4)
        layout.setSpacing(10)

        # Whale avatar label
        avatar = QLabel()
        avatar.setFixedSize(36, 36)
        avatar.setAlignment(Qt.AlignTop | Qt.AlignHCenter)
        # Draw avatar with cyan border ring
        ring_px = QPixmap(36, 36)
        ring_px.fill(Qt.transparent)
        p = QPainter(ring_px)
        p.setRenderHint(QPainter.Antialiasing)
        # Cyan ring background
        p.setBrush(QBrush(QColor(0,183,212,60)))
        p.setPen(QPen(QColor(0,229,255,120), 1.5))
        p.drawEllipse(1,1,33,33)
        # Draw whale centered
        px = AIMessageWidget._whale_px.scaled(28,28,Qt.KeepAspectRatio,Qt.SmoothTransformation)
        p.drawPixmap(4, 4, px)
        p.end()
        avatar.setPixmap(ring_px)
        layout.addWidget(avatar, 0, Qt.AlignTop)

        # Message bubble
        bubble = QWidget()
        bubble.setStyleSheet("""
            background: #111820;
            border: 1px solid #1e2d3d;
            border-left: 2px solid #00b8d4;
            border-radius: 8px;
        """)
        b_layout = QVBoxLayout(bubble)
        b_layout.setContentsMargins(10, 6, 10, 6)
        b_layout.setSpacing(0)

        label = QLabel()
        label.setFont(QFont("Courier New", 12))
        label.setWordWrap(True)
        label.setStyleSheet("background: transparent; border: none;")
        lines = text.split("\n")
        html_lines = []
        for line in lines:
            if line.startswith(">"):
                html_lines.append(f'<span style="color:#00e5ff;">{line}</span>')
            else:
                html_lines.append(f'<span style="color:#8ab4c8;">{line}</span>')
        label.setText("<br>".join(html_lines))
        label.setTextFormat(Qt.RichText)
        b_layout.addWidget(label)

        layout.addWidget(bubble, 1)


