# ─── Chat Output Area ───────────────────────────────────────────────────────────
class ChatOutput(QScrollArea):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setWidgetResizable(True)
        self.setHorizontalScrollBarPolicy(Qt.ScrollBarAlwaysOff)
        self.setVerticalScrollBarPolicy(Qt.ScrollBarAsNeeded)
        self.setFrameShape(QFrame.NoFrame)
        self.setStyleSheet("""
            QScrollArea { background: transparent; border: none; }
            QScrollBar:vertical { background: transparent; width: 4px; margin: 0; }
            QScrollBar::handle:vertical { background: #1a2535; border-radius: 2px; min-height: 20px; }
            QScrollBar::add-line:vertical, QScrollBar::sub-line:vertical { height: 0; }
        """)
        self.container = QWidget()
        self.container.setStyleSheet("background: transparent;")
        self.v_layout = QVBoxLayout(self.container)
        self.v_layout.setContentsMargins(20, 16, 20, 8)
        self.v_layout.setSpacing(2)
        self.v_layout.addStretch()
        self.setWidget(self.container)

        self.cursor_label = QLabel("█")
        self.cursor_label.setFont(QFont("Courier New", 13))
        self.cursor_label.setStyleSheet("color: #00e5ff; background: transparent;")
        self.cursor_label.setFixedHeight(20)
        self.v_layout.addWidget(self.cursor_label)
        self.cursor_label.hide()

        self._cursor_visible = True
        self.cursor_timer = QTimer(self)
        self.cursor_timer.timeout.connect(self._blink_cursor)

        self.separator = QFrame()
        self.separator.setFixedHeight(1)
        self.separator.setStyleSheet("background: qlineargradient(x1:0,y1:0,x2:1,y2:0, stop:0 #00e5ff44, stop:1 transparent);")
        self.separator.hide()

    def start_cursor(self):
        self.cursor_label.show()
        self.cursor_timer.start(530)

    def show_separator(self):
        idx = self.v_layout.indexOf(self.cursor_label)
        self.v_layout.insertWidget(idx, self.separator)
        self.separator.show()

    def _blink_cursor(self):
        self._cursor_visible = not self._cursor_visible
        self.cursor_label.setText("█" if self._cursor_visible else " ")

    def add_boot_line(self, text: str, style: str):
        label = QLabel()
        label.setFont(QFont("Courier New", 13))
        label.setStyleSheet("background: transparent;")
        label.setTextFormat(Qt.RichText)
        label.setWordWrap(True)
        if style == "normal":
            label.setText(f'<span style="color:#c8d8e0;">{text}</span>')
        elif style == "cyan":
            label.setText(f'<span style="color:#00e5ff;">{text}</span>')
        elif style == "kv":
            parts = text.split(": ", 1)
            if len(parts) == 2:
                label.setText(f'<span style="color:#c8d8e0;">{parts[0]}: </span><span style="color:#00e5ff;">{parts[1]}</span>')
            else:
                label.setText(f'<span style="color:#c8d8e0;">{text}</span>')
        idx = self.v_layout.indexOf(self.cursor_label)
        self.v_layout.insertWidget(idx, label)
        self.scroll_to_bottom()

    def add_message(self, msg_type: str, text: str, time_str: str):
        if msg_type == "user":
            w = UserMessageWidget(text, time_str)
        else:
            w = AIMessageWidget(text, time_str)
        idx = self.v_layout.indexOf(self.cursor_label)
        self.v_layout.insertWidget(idx, w)
        self.scroll_to_bottom()

    def scroll_to_bottom(self):
        QTimer.singleShot(50, lambda: self.verticalScrollBar().setValue(
            self.verticalScrollBar().maximum()))


# ─── Main Window ────────────────────────────────────────────────────────────────
class MechForgeWindow(QMainWindow):
    def __init__(self):
        super().__init__()
        self.setWindowTitle("MechForge AI")
        self.setFixedSize(900, 620)
        self.setWindowFlags(Qt.FramelessWindowHint | Qt.Window)
        self.setAttribute(Qt.WA_TranslucentBackground)
        self._drag_pos = None
        self._build_ui()
        self._start_boot_sequence()

    def _build_ui(self):
        central = QWidget()
        central.setObjectName("central")
        central.setStyleSheet("#central { background: #0d1117; border: 1px solid #1e2d3d; border-radius: 8px; }")
        self.setCentralWidget(central)
        root = QVBoxLayout(central)
        root.setContentsMargins(0,0,0,0)
        root.setSpacing(0)
        root.addWidget(self._build_titlebar())
        body_widget = QWidget()
        body_widget.setStyleSheet("background: transparent;")
        body = QHBoxLayout(body_widget)
        body.setContentsMargins(0,0,0,0)
        body.setSpacing(0)
        body.addWidget(self._build_sidebar())
        body.addWidget(self._build_main_panel(), 1)
        root.addWidget(body_widget, 1)
        root.addWidget(self._build_statusbar())
        self.setStyleSheet("QMainWindow { background: transparent; }")

    def _build_titlebar(self):
        bar = QWidget()
        bar.setFixedHeight(44)
        bar.setStyleSheet("background: #0d1117; border-bottom: 1px solid #1a2535;")
        layout = QHBoxLayout(bar)
        layout.setContentsMargins(16,0,12,0)
        layout.setSpacing(8)

        # Whale logo in title bar
        whale_logo = QLabel()
        whale_logo.setFixedSize(30, 30)
        px = load_whale_pixmap(30)
        # Add gradient bg
        bg_px = QPixmap(30,30)
        bg_px.fill(Qt.transparent)
        p = QPainter(bg_px)
        p.setRenderHint(QPainter.Antialiasing)
        grad = QLinearGradient(0,0,30,30)
        grad.setColorAt(0, QColor("#00b8d4")); grad.setColorAt(1, QColor("#0097a7"))
        p.setBrush(QBrush(grad)); p.setPen(Qt.NoPen)
        p.drawRoundedRect(0,0,30,30,6,6)
        p.drawPixmap(0,0,px)
        p.end()
        whale_logo.setPixmap(bg_px)
        layout.addWidget(whale_logo)

        title = QLabel("MechForge AI")
        title.setFont(QFont("Arial", 13, QFont.Bold))
        title.setStyleSheet("color: #c8d8e0; letter-spacing: 1px; background: transparent;")
        layout.addWidget(title)
        version = QLabel("v0.5.0")
        version.setFont(QFont("Courier New", 11))
        version.setStyleSheet("color: #3a5068; background: transparent;")
        layout.addWidget(version)
        layout.addStretch()
        for sym, tip in [("−","min"),("□","max"),("×","close")]:
            btn = QPushButton(sym)
            btn.setFixedSize(24,24)
            btn.setCursor(QCursor(Qt.PointingHandCursor))
            btn.setStyleSheet("QPushButton { background: transparent; border: none; color: #3a5068; font-size: 14px; } QPushButton:hover { color: #00e5ff; }")
            if tip == "close": btn.clicked.connect(self.close)
            elif tip == "min": btn.clicked.connect(self.showMinimized)
            layout.addWidget(btn)
        return bar

    def _build_sidebar(self):
        sidebar = QWidget()
        sidebar.setFixedWidth(68)
        sidebar.setStyleSheet("background: #0a0e14; border-right: 1px solid #1a2535;")
        layout = QVBoxLayout(sidebar)
        layout.setContentsMargins(8,12,8,12)
        layout.setSpacing(4)

        self.whale_btn = WhaleAvatarButton()
        self.whale_btn.setActive(True)
        self.whale_btn.clicked.connect(lambda: self._on_sidebar_click("assistant"))
        layout.addWidget(self.whale_btn, 0, Qt.AlignHCenter)

        self.sidebar_buttons = {"assistant": self.whale_btn}
        for icon_id in ["shield","doc","scan","plugin","db"]:
            btn = SidebarButton(icon_id)
            btn.setActive(False)
            btn.clicked.connect(lambda checked, iid=icon_id: self._on_sidebar_click(iid))
            self.sidebar_buttons[icon_id] = btn
            layout.addWidget(btn, 0, Qt.AlignHCenter)

        layout.addStretch()
        return sidebar

    def _build_main_panel(self):
        panel = QWidget()
        panel.setStyleSheet("background: #0d1117;")
        layout = QVBoxLayout(panel)
        layout.setContentsMargins(0,0,0,0)
        layout.setSpacing(0)
        self.bg_widget = HexGridWidget(panel)
        self.bg_widget.setAttribute(Qt.WA_TransparentForMouseEvents)
        self.chat_output = ChatOutput()
        layout.addWidget(self.chat_output, 1)
        layout.addWidget(self._build_input_row())
        return panel

    def _build_input_row(self):
        row = QWidget()
        row.setFixedHeight(56)
        row.setStyleSheet("background: #0d1117; border-top: 1px solid #1a2535;")
        layout = QHBoxLayout(row)
        layout.setContentsMargins(12,8,12,8)
        container = QWidget()
        container.setStyleSheet("background: #111820; border: 1px solid #1e2d3d; border-radius: 20px;")
        c_layout = QHBoxLayout(container)
        c_layout.setContentsMargins(14,0,6,0)
        c_layout.setSpacing(8)
        self.input_field = QLineEdit()
        self.input_field.setPlaceholderText("Type your query here...")
        self.input_field.setFont(QFont("Courier New", 12))
        self.input_field.setStyleSheet("QLineEdit { background: transparent; border: none; color: #c8d8e0; } QLineEdit::placeholder { color: #3a6070; }")
        self.input_field.returnPressed.connect(self._on_send)
        c_layout.addWidget(self.input_field, 1)
        send_btn = QPushButton("  ➤  Send")
        send_btn.setFixedSize(90, 32)
        send_btn.setFont(QFont("Arial", 12, QFont.Bold))
        send_btn.setCursor(QCursor(Qt.PointingHandCursor))
        send_btn.setStyleSheet("QPushButton { background: qlineargradient(x1:0,y1:0,x2:1,y2:1, stop:0 #00b8d4, stop:1 #0097a7); color: white; border: none; border-radius: 16px; font-size: 12px; font-weight: bold; } QPushButton:hover { background: qlineargradient(x1:0,y1:0,x2:1,y2:1, stop:0 #00e5ff, stop:1 #00b8d4); }")
        send_btn.clicked.connect(self._on_send)
        c_layout.addWidget(send_btn)
        layout.addWidget(container, 1)
        return row

    def _build_statusbar(self):
        bar = QWidget()
        bar.setFixedHeight(32)
        bar.setStyleSheet("background: #080c10; border-top: 1px solid #1a2535;")
        layout = QHBoxLayout(bar)
        layout.setContentsMargins(16,0,16,0)
        layout.setSpacing(0)

        # Tiny whale in status bar
        whale_tiny = QLabel()
        whale_tiny.setFixedSize(18,18)
        whale_tiny.setPixmap(load_whale_pixmap(18))
        layout.addWidget(whale_tiny)
        layout.addSpacing(4)

        def lbl(text, color="#3a6070", bold=False):
            l = QLabel(text)
            l.setFont(QFont("Courier New", 10, QFont.Bold if bold else QFont.Normal))
            l.setStyleSheet(f"color: {color}; background: transparent;")
            return l

        layout.addWidget(lbl("MechForge", "#00b8d4", bold=True))
        layout.addSpacing(4)
        for k,v,vc in [("API","Ollama","#3a6070"),("Model","qwen2.5:3b","#3a6070"),("RAG","ON","#00e5ff"),("Memory","42 KB","#3a6070")]:
            layout.addWidget(lbl(f"  |  {k}: ","#3a6070"))
            layout.addWidget(lbl(v, vc))
        layout.addStretch()
        for sym in ["◇","≡","+","○"]:
            l = lbl(sym); l.setFixedWidth(20); l.setAlignment(Qt.AlignCenter)
            layout.addWidget(l)
        return bar

    def _start_boot_sequence(self):
        now = datetime.now().strftime("%H:%M")
        for i, line_def in enumerate(BOOT_LINES):
            text = line_def["text"].replace("{time}", now)
            QTimer.singleShot(line_def["delay"],
                lambda t=text, s=line_def["style"], last=(i==len(BOOT_LINES)-1):
                    self._show_boot_line(t, s, last))

    def _show_boot_line(self, text, style, is_last):
        self.chat_output.add_boot_line(text, style)
        if is_last:
            QTimer.singleShot(200, self._on_boot_complete)

    def _on_boot_complete(self):
        self.chat_output.show_separator()
        self.chat_output.start_cursor()

    def _on_sidebar_click(self, icon_id):
        for bid, btn in self.sidebar_buttons.items():
            btn.setActive(bid == icon_id)

    def _on_send(self):
        text = self.input_field.text().strip()
        if not text: return
        now = datetime.now().strftime("%H:%M")
        time_str = f"[{now}]"
        self.chat_output.add_message("user", text, time_str)
        self.input_field.clear()
        query = text
        QTimer.singleShot(800, lambda: self.chat_output.add_message(
            "ai",
            f'Processing query: "{query}"\n> Analysis complete. RAG retrieval active.\nResponse generated by qwen2.5:3b.',
            time_str))

    def resizeEvent(self, e):
        super().resizeEvent(e)
        if hasattr(self, "bg_widget"):
            self.bg_widget.resize(self.centralWidget().size())

    def mousePressEvent(self, e):
        if e.button() == Qt.LeftButton:
            self._drag_pos = e.globalPosition().toPoint() - self.frameGeometry().topLeft()

    def mouseMoveEvent(self, e):
        if e.buttons() == Qt.LeftButton and self._drag_pos:
            self.move(e.globalPosition().toPoint() - self._drag_pos)

    def mouseReleaseEvent(self, e):
        self._drag_pos = None

    def paintEvent(self, e):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.Antialiasing)
        glow = QColor(0, 229, 255, 12)
        for i in range(8, 0, -1):
            painter.setPen(QPen(glow, i*2))
            painter.setBrush(Qt.NoBrush)
            painter.drawRoundedRect(i,i,self.width()-i*2,self.height()-i*2,9,9)
        painter.end()


def main():
    app = QApplication(sys.argv)
    app.setStyle("Fusion")
    palette = QPalette()
    palette.setColor(QPalette.Window, QColor("#0d1117"))
    palette.setColor(QPalette.WindowText, QColor("#c8d8e0"))
    palette.setColor(QPalette.Base, QColor("#111820"))
    palette.setColor(QPalette.Text, QColor("#c8d8e0"))
    palette.setColor(QPalette.Button, QColor("#0d1117"))
    palette.setColor(QPalette.ButtonText, QColor("#c8d8e0"))
    palette.setColor(QPalette.Highlight, QColor("#00b8d4"))
    palette.setColor(QPalette.HighlightedText, QColor("#ffffff"))
    app.setPalette(palette)
    win = MechForgeWindow()
    win.show()
    sys.exit(app.exec())

if __name__ == "__main__":
    main()